import{_ as o,o as t,c as a,ag as r}from"./chunks/framework.ePeAWSvT.js";const p=JSON.parse('{"title":"Troubleshooting & FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"guide/troubleshooting.md","filePath":"guide/troubleshooting.md"}'),n={name:"guide/troubleshooting.md"};function i(s,e,l,c,d,h){return t(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="troubleshooting-faq" tabindex="-1">Troubleshooting &amp; FAQ <a class="header-anchor" href="#troubleshooting-faq" aria-label="Permalink to &quot;Troubleshooting &amp; FAQ&quot;">​</a></h1><h2 id="why-is-a-panel-empty" tabindex="-1">&quot;Why is a panel empty?&quot; <a class="header-anchor" href="#why-is-a-panel-empty" aria-label="Permalink to &quot;&quot;Why is a panel empty?&quot;&quot;">​</a></h2><p>Panels show the WakeUp screen (home panel) when no mnemonic has been set.<br><strong>Solution:</strong> Type any command + GO. E.g. <code>WEI GO</code> or <code>AAPL US DES GO</code>.</p><p>If a function shows &quot;UNKNOWN MNEMONIC&quot;, the code is not in the catalog.<br><strong>Solution:</strong> Use Ctrl+K to search for similar functions, or browse NAVTREE GO.</p><h2 id="why-is-data-showing-sim-or-stale" tabindex="-1">&quot;Why is data showing SIM or STALE?&quot; <a class="header-anchor" href="#why-is-data-showing-sim-or-stale" aria-label="Permalink to &quot;&quot;Why is data showing SIM or STALE?&quot;&quot;">​</a></h2><p>All data in MarketMind Terminal is <strong>simulated</strong> (SIM) by design for the demo platform.<br> STALE means the simulated value hasn&#39;t refreshed within its expected cadence.<br><strong>Solution:</strong> Enable <strong>Live Mode</strong> via PREF GO or the DOCK panel. Or reload the panel.</p><h2 id="why-can-t-i-access-a-function" tabindex="-1">&quot;Why can&#39;t I access a function?&quot; <a class="header-anchor" href="#why-can-t-i-access-a-function" aria-label="Permalink to &quot;&quot;Why can&#39;t I access a function?&quot;&quot;">​</a></h2><p>A policy block prevents access. Check the <strong>ERR console</strong> for the block message.<br><strong>Solution:</strong></p><ol><li><code>COMP GO</code> → check current compliance mode</li><li><code>POL GO</code> → check policy rules</li><li><code>ENT GO</code> → check entitlements for your role</li></ol><h2 id="why-is-my-drill-not-working" tabindex="-1">&quot;Why is my drill not working?&quot; <a class="header-anchor" href="#why-is-my-drill-not-working" aria-label="Permalink to &quot;&quot;Why is my drill not working?&quot;&quot;">​</a></h2><p>If clicking a row does nothing:</p><ul><li>The row may not have an entity assigned (informational row)</li><li>The function may be a stub (shows enterprise scaffold screen)</li></ul><p><strong>Solution:</strong> Right-click the row to see available context menu actions.<br> Or <strong>Alt+Click</strong> to try the Inspector overlay on that row.</p><h2 id="why-is-there-no-data-in-my-monitor" tabindex="-1">&quot;Why is there no data in my monitor?&quot; <a class="header-anchor" href="#why-is-there-no-data-in-my-monitor" aria-label="Permalink to &quot;&quot;Why is there no data in my monitor?&quot;&quot;">​</a></h2><p>MON requires securities to be added manually.<br><strong>Solution:</strong> Type symbols in the add field (e.g. <code>AAPL US Equity</code>) and press Enter.<br> Or use MON+ GO to use the Monitor Builder with custom field columns.</p><h2 id="why-are-workspaces-not-loading" tabindex="-1">&quot;Why are workspaces not loading?&quot; <a class="header-anchor" href="#why-are-workspaces-not-loading" aria-label="Permalink to &quot;&quot;Why are workspaces not loading?&quot;&quot;">​</a></h2><p>Workspaces are stored in localStorage.<br><strong>Solution:</strong> Check that you&#39;re using the exact same workspace name.<br> Type <code>WS GO</code> to see all saved workspaces and their dates.</p><h2 id="performance-is-slow-ui-is-janky" tabindex="-1">&quot;Performance is slow / UI is janky&quot; <a class="header-anchor" href="#performance-is-slow-ui-is-janky" aria-label="Permalink to &quot;&quot;Performance is slow / UI is janky&quot;&quot;">​</a></h2><ol><li>Disable Live Mode: <code>PREF GO</code> → toggle off</li><li>Reduce pane count: close unused panes with ✕ button</li><li>Use Compact density: <code>PREF GO</code> → select Compact</li><li>Check diagnostics: <code>DIAG GO</code> — shows FPS and render time per pane</li></ol><h2 id="the-map-geo-isn-t-loading" tabindex="-1">&quot;The map (GEO) isn&#39;t loading&quot; <a class="header-anchor" href="#the-map-geo-isn-t-loading" aria-label="Permalink to &quot;&quot;The map (GEO) isn&#39;t loading&quot;&quot;">​</a></h2><p>The global map requires MapLibre GL tile loading from external CDN.<br><strong>Solution:</strong> Check internet connection. First load may take 2–5 seconds.<br> If tiles don&#39;t appear, the map still works — country overlays are rendered client-side.</p><h2 id="kill-switch-was-triggered-—-can-t-place-orders" tabindex="-1">&quot;KILL switch was triggered — can&#39;t place orders&quot; <a class="header-anchor" href="#kill-switch-was-triggered-—-can-t-place-orders" aria-label="Permalink to &quot;&quot;KILL switch was triggered — can&#39;t place orders&quot;&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes tokyo-night tokyo-night vp-code" tabindex="0"><code><span class="line"><span>KILL GO → view kill switch status</span></span>
<span class="line"><span>COMP GO → reset compliance mode</span></span></code></pre></div><p>Ensure compliance mode is set to &quot;normal&quot; in COMP panel.</p><h2 id="error-reference" tabindex="-1">Error Reference <a class="header-anchor" href="#error-reference" aria-label="Permalink to &quot;Error Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Error Type</th><th>Meaning</th></tr></thead><tbody><tr><td><code>PARSER</code></td><td>Command could not be parsed. Use format: TICKER MARKET MNEMONIC GO</td></tr><tr><td><code>POLICY</code></td><td>Action blocked by policy rule. Check COMP/POL</td></tr><tr><td><code>STORAGE</code></td><td>localStorage operation failed. Check browser quota</td></tr><tr><td><code>POLICY_BLOCK</code></td><td>Specific action blocked for your role. Check ENT</td></tr></tbody></table>`,26)])])}const m=o(n,[["render",i]]);export{p as __pageData,m as default};
